@js:
try {
    // 1. 解析当前网页的视频直链
    const jsonStr = result.split('var player_aaaa=')[1].split('</script>')[0].trim().replace(/;$/, "");
    const data = JSON.parse(jsonStr);
    let m3u8 = data.url;

    if (data.encrypt == 1) { 
        m3u8 = unescape(m3u8); 
    } else if (data.encrypt == 2) { 
        m3u8 = unescape(atob(m3u8)); 
    }

    // 2. 校验并调用第三方播放器接口
    if (!m3u8 || m3u8 === "") {
        "未获取到视频地址";
    } else {
        const qianqiApi = "https://api.qianqi.net/vip/?url=";
        const playUrl = qianqiApi + java.encodeURI(m3u8);

        // 核心突破：直接调用开源阅读的浏览器接口强行弹窗播放
        java.startBrowserAwait(playUrl, book.name);

        // 唤起播放器后，正文显示为空即可，避免多余渲染
        ""; 
    }
} catch (err) {
    "代码执行/解析失败: " + err.message;
}
